import React, { useContext } from "react";
import { Link, graphql } from "gatsby";
import Layout, { LangContext } from "../components/Layout";
import SEO from "../components/SEO";
import DataPanel from "../components/DataPanel";
import { pickLangNodes, langSlug } from "../utils/i18n";

const LegalPage = ({ data }) => {
  const { lang } = useContext(LangContext);
  const reports = pickLangNodes(data.daily.nodes, lang);
  const onDemand = pickLangNodes(data.onDemand.nodes, lang);
  const latest = reports[0];

  const l = (vi, en) => lang === "vi" ? vi : en;
  const title = l("⚖️ Theo dõi Pháp lý Việt Nam", "⚖️ Vietnam Legal Watch");
  const subtitle = l("Cập nhật quy định, thay đổi pháp lý & thông tin tuân thủ", "Regulatory changes, legal updates & compliance intelligence for Vietnam");
  const viewFull = l("Xem báo cáo đầy đủ →", "View full report →");
  const specialLabel = l("🔍 Phân tích Đặc biệt", "🔍 Special Analyses");
  const dailyLabel = l("📋 Bản tin Pháp lý Hàng ngày", "📋 Daily Legal Briefings");
  const latestLabel = l("⚖️ Mới nhất", "⚖️ Latest");

  return (
    <Layout>
      <div className="page-header">
        <h1>{title}</h1>
        <p className="page-subtitle">{subtitle}</p>
      </div>

      <div className="opp-grid">
        {latest && (
          <DataPanel title={`${latestLabel} — ${latest.fields?.date || ""}`}>
            <div className="report-content markdown-body">
              <div dangerouslySetInnerHTML={{ __html: latest.html || `<p>${l("Chưa có báo cáo.", "No report available.")}</p>` }} />
            </div>
            {latest.fields?.slug && (
              <Link to={langSlug(latest.fields.slug, lang)} className="view-all" style={{ marginTop: "12px", display: "inline-block" }}>
                {viewFull}
              </Link>
            )}
          </DataPanel>
        )}

        <div className="side-panels">
          {onDemand.length > 0 && (
            <DataPanel title={specialLabel}>
              <div className="report-list">
                {onDemand.map((report) => (
                  <Link key={report.id} to={langSlug(report.fields?.slug || "/", lang)} className="report-list-item">
                    <span className="report-date">{report.fields?.date || "—"}</span>
                    <span className="report-title">
                      {report.fields?.inferredTitle || "Legal Analysis"}
                    </span>
                  </Link>
                ))}
              </div>
            </DataPanel>
          )}

          <DataPanel title={dailyLabel}>
            <div className="report-list">
              {reports.slice(0, 12).map((report) => (
                <Link key={report.id} to={langSlug(report.fields?.slug || "/", lang)} className="report-list-item">
                  <span className="report-date">{report.fields?.date || "—"}</span>
                  <span className="report-title">
                    {report.fields?.inferredTitle || "Legal Briefing"}
                  </span>
                </Link>
              ))}
            </div>
          </DataPanel>
        </div>
      </div>
    </Layout>
  );
};

export default LegalPage;

export const Head = ({ location }) => {
  const lang = location?.pathname?.startsWith("/en") ? "en" : "vi";
  return (
    <SEO
      title={lang === "vi" ? "Theo dõi Pháp lý Việt Nam — Bobbie Intelligence" : "Vietnam Legal Watch — Bobbie Intelligence"}
      description={lang === "vi"
        ? "Theo dõi pháp lý và quy định Việt Nam hàng ngày: luật mới, nghị định, thông tư và thay đổi tuân thủ."
        : "Daily Vietnamese legal and regulatory monitoring: new laws, decrees, circulars, and compliance changes."}
      path="/legal/"
      lang={lang}
    />
  );
};

export const query = graphql`
  query LegalPage {
    daily: allMarkdownRemark(
      filter: { fields: { category: { eq: "vn-legal-watch" }, reportType: { eq: "daily" } } }
      sort: { fields: { date: DESC } }
      limit: 20
    ) {
      nodes {
        id
        html
        fields {
          slug
          date
          inferredTitle
          lang
          baseName
        }
      }
    }
    onDemand: allMarkdownRemark(
      filter: { fields: { category: { eq: "vn-legal-watch" }, reportType: { eq: "on-demand" } } }
      sort: { fields: { date: DESC } }
    ) {
      nodes {
        id
        fields {
          slug
          date
          inferredTitle
          lang
          baseName
        }
      }
    }
  }
`;
